import{_ as r,o as a,c as o,a1 as l}from"./chunks/framework.BmLW0N4k.js";const c=JSON.parse('{"title":"研究・スキルツリー・専門家ガイド","description":"","frontmatter":{},"headers":[],"relativePath":"guide/research-guide.md","filePath":"guide/research-guide.md"}'),n={name:"guide/research-guide.md"};function i(e,t,s,h,d,g){return a(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="研究・スキルツリー・専門家ガイド" tabindex="-1">研究・スキルツリー・専門家ガイド <a class="header-anchor" href="#研究・スキルツリー・専門家ガイド" aria-label="Permalink to &quot;研究・スキルツリー・専門家ガイド&quot;">​</a></h1><blockquote><p>このページはインターネット上の攻略情報を集約した内容です。未検証の情報を含む場合があります。</p></blockquote><hr><h2 id="研究システムの仕組み-スキルツリー" tabindex="-1">研究システムの仕組み（スキルツリー） <a class="header-anchor" href="#研究システムの仕組み-スキルツリー" aria-label="Permalink to &quot;研究システムの仕組み（スキルツリー）&quot;">​</a></h2><ul><li>研究は「<strong>スキルツリー</strong>」をアンロックしていき、生産効率・選択肢・都市サービスを拡張する仕組み。アンロックした内容は<strong>全島で共有</strong>されます。</li><li>ツリーは大きく <strong>経済 / 社会 / 軍事</strong> の3トラック＋<strong>DLC「灰の予言」ブランチ</strong>の計4系統。150以上のスキルが存在します。</li><li><strong>排他的な分岐は無い</strong>。時間をかければすべてアンロック可能です。</li><li>複数の技術を<strong>順番にキューへ積める</strong>。研究速度は都市が産出する知識量に比例します。</li></ul><h3 id="インスピレーション-研究の解放ゲート" tabindex="-1">インスピレーション（研究の解放ゲート） <a class="header-anchor" href="#インスピレーション-研究の解放ゲート" aria-label="Permalink to &quot;インスピレーション（研究の解放ゲート）&quot;">​</a></h3><ul><li>ツリーの深部を開くには「<strong>インスピレーション</strong>」の条件を満たす必要があります。条件例: 交易ルート数・水道橋の建設数・都市ステータス。</li><li>例として「国際交易ルート5本」「研究ポイント17,000産出」などが研究解放条件として挙がります。</li></ul><hr><h2 id="知識ポイントの入手" tabindex="-1">知識ポイントの入手 <a class="header-anchor" href="#知識ポイントの入手" aria-label="Permalink to &quot;知識ポイントの入手&quot;">​</a></h2><p>知識はAnno 117の8つのコア属性のひとつ（人口・収入・信仰・知識・名声・健康・幸福・火災安全）。知識が高いほど研究速度が上がります。</p><h3 id="知識を産む主な建物" tabindex="-1">知識を産む主な建物 <a class="header-anchor" href="#知識を産む主な建物" aria-label="Permalink to &quot;知識を産む主な建物&quot;">​</a></h3><ul><li><strong>ラテン語学校</strong> — プレブス向けの公共サービス。範囲内の建物に<strong>知識 +3</strong>。最初に知識を上げる建物のひとつ。住宅密集地の近くに配置し、効果範囲が多くの家をカバーするよう配置するのが推奨です。</li><li><strong>図書館</strong> — 大きな知識ボーナスを与えます（<strong>知識 +7</strong>）。</li><li><strong>聖所</strong> — ケルト系の公共サービス建物。信仰 +2 / 知識 +1。序盤に知識を底上げするもうひとつの選択肢。</li></ul><h3 id="需要を満たすと増加する知識" tabindex="-1">需要を満たすと増加する知識 <a class="header-anchor" href="#需要を満たすと増加する知識" aria-label="Permalink to &quot;需要を満たすと増加する知識&quot;">​</a></h3><ul><li><strong>筆記板</strong> — エクィテスの需要。供給すると知識 +3。</li><li><strong>竪琴</strong> — パトリキの需要。供給すると知識 +2。</li><li><strong>手鏡</strong> — パトリキの需要。供給すると知識 +2。</li></ul><h3 id="知識を増やすコツ" tabindex="-1">知識を増やすコツ <a class="header-anchor" href="#知識を増やすコツ" aria-label="Permalink to &quot;知識を増やすコツ&quot;">​</a></h3><ul><li>守護神<strong>ミネルヴァ</strong>を島の守護神に設定し「神の英知」を得ると、信仰の数値によりその島の全住民の基礎知識が増加します（最大 +13）。</li><li>専門家<strong>頭韻の文学者 ホラティア・ヘミナ</strong> — 筆記板工房の知識産出 +3。</li></ul><hr><h2 id="研究ツリーの種類-トラック別の内容" tabindex="-1">研究ツリーの種類（トラック別の内容） <a class="header-anchor" href="#研究ツリーの種類-トラック別の内容" aria-label="Permalink to &quot;研究ツリーの種類（トラック別の内容）&quot;">​</a></h2><h3 id="経済" tabindex="-1">経済 <a class="header-anchor" href="#経済" aria-label="Permalink to &quot;経済&quot;">​</a></h3><p>物流・生産アップグレード・資源アクセス・道路改善。具体内容: 交易インフラ・林業管理・農業灌漑・鉱業強化・倉庫容量拡張など。</p><p>序盤推奨ノード:</p><ul><li><strong>倉庫/集積所</strong> — 島の保管容量を増加。基礎ノード。</li><li><strong>交易所改良</strong> — 交易所の効率と保管容量を強化・収入増。</li><li><strong>裁縫サークル</strong> — 糸紡ぎ師の知識産出を上げるため序盤に有用。</li><li><strong>舗装道路</strong> — 輸送速度と建物のストリート範囲を増加（手動アップグレードが必要）。</li><li><strong>大地の血</strong> — 鉱床の無い島で鉄を低レートで採掘可能にします。</li><li><strong>緑地の再生</strong> — 草原に木こりを配置でき、配置の自由度が上がります。</li><li><strong>森林再生</strong> — 炭焼き小屋が草原に配置でき、配置の自由度が上がります。</li></ul><h3 id="社会" tabindex="-1">社会 <a class="header-anchor" href="#社会" aria-label="Permalink to &quot;社会&quot;">​</a></h3><p>公共サービス・都市範囲/ユーティリティ・修理・維持オプション・生活の質向上。災害対策・市場効果・船の改良・NPC同盟（従属）条約など。</p><p>序盤推奨ノード:</p><ul><li><strong>市場の力</strong> — 市場の効果範囲を増加。</li><li><strong>需品管理</strong> — 船の積荷スロット増・積荷重量減。交易を円滑化し、衛生・防火改善へ繋がります。</li></ul><h3 id="軍事" tabindex="-1">軍事 <a class="header-anchor" href="#軍事" aria-label="Permalink to &quot;軍事&quot;">​</a></h3><p>ユニット性能・士気・耐久・遠征支援。兵営・防御構造物・新ユニット（投石兵 / ローマ軍団兵）・海軍アップグレードなど。</p><ul><li>軍事は<strong>後回し推奨</strong>。軍隊は人口・船・資金を要するため、都市が黒字で安定してから着手しましょう。</li></ul><h3 id="序盤の全体方針" tabindex="-1">序盤の全体方針 <a class="header-anchor" href="#序盤の全体方針" aria-label="Permalink to &quot;序盤の全体方針&quot;">​</a></h3><p><strong>経済 + 社会を先に</strong>進め、軍事は都市が安定してから。現在のボトルネックを解消する1トラックに集中するとよいでしょう。</p><hr><h2 id="専門家" tabindex="-1">専門家 <a class="header-anchor" href="#専門家" aria-label="Permalink to &quot;専門家&quot;">​</a></h2><p>前作Anno 1800の「アイテム」が本作では<strong>専門家</strong>に名称変更。建物や船のスロットに装着して<strong>範囲バフ</strong>を与えるカード的存在です。詳しいデータは<a href="/wiki/items.html">アイテム一覧</a>を参照してください。</p><h3 id="レアリティ" tabindex="-1">レアリティ <a class="header-anchor" href="#レアリティ" aria-label="Permalink to &quot;レアリティ&quot;">​</a></h3><p>5段階: <strong>コモン / レア / エピック / レジェンダリー / ユニーク</strong>。高レアほど効果が強く、入手難度も高くなります。</p><h3 id="カテゴリ-専門分野" tabindex="-1">カテゴリ（専門分野） <a class="header-anchor" href="#カテゴリ-専門分野" aria-label="Permalink to &quot;カテゴリ（専門分野）&quot;">​</a></h3><p><strong>財政 / 宗教 / 研究 / 文化 / 経済 / 自然 / 社会 / 軍事 / 航海</strong></p><h3 id="装着先とスロット数" tabindex="-1">装着先とスロット数 <a class="header-anchor" href="#装着先とスロット数" aria-label="Permalink to &quot;装着先とスロット数&quot;">​</a></h3><table tabindex="0"><thead><tr><th>装着先</th><th>スロット数</th><th>備考</th></tr></thead><tbody><tr><td><strong>総督のヴィラ</strong></td><td>標準5スロット、名声で増加</td><td>効果範囲が広い。汎用・共通属性バフ向き。住宅地近くに配置。</td></tr><tr><td><strong>オフィキウム</strong></td><td>2スロット → 研究進行で3スロット</td><td>効果範囲が狭い。建設可能数は島の名声とスキルに依存。ヴィラや他のオフィキウムと範囲を重複させられない。生産系の特化バフ（労働力削減・維持費削減）向きで生産建物の周りに配置。</td></tr><tr><td><strong>船</strong></td><td>専用の船長スロット1つ</td><td><strong>船長</strong>を装着。その船にのみ効果。</td></tr></tbody></table><h3 id="効果の仕組み" tabindex="-1">効果の仕組み <a class="header-anchor" href="#効果の仕組み" aria-label="Permalink to &quot;効果の仕組み&quot;">​</a></h3><ul><li>専門家は<strong>範囲内の建物数に応じて</strong>バフ量が決まります。密集配置ほど効率が上がります。</li><li>効果対象: 住宅・生産建物・公共サービス建物・船。</li><li>効果の種類: 生産性 +10%〜+35%、労働力 -25%〜-80%、維持費 -25%〜-80%、属性ボーナス（人口・信仰・知識・健康・幸福・火災安全・収入・名声）、特殊効果（例: 10サイクルごとに追加1t）など。</li></ul><h3 id="入手方法" tabindex="-1">入手方法 <a class="header-anchor" href="#入手方法" aria-label="Permalink to &quot;入手方法&quot;">​</a></h3><ul><li><strong>クエスト/イベント</strong> — 専用クエストやイベントの報酬。最初の専門家を無料で1体得られることも。</li><li><strong>交易商</strong> — ラティウム / アルビオン等の商人からデナリウスで購入（アイテムタブ）。来訪中の専門家を雇用。</li><li><strong>スキルツリー</strong> — 特定の経済/社会/軍事の研究で専門家をアンロック。</li><li><strong>殿堂</strong> — 統計メニュー内。名声ポイントで購入、または実績達成で高レア入手。</li><li><strong>祭礼</strong> — 開催するとランダムな専門家・船長がゲストとして確率で来訪。</li><li><strong>灯台の契約</strong> — 他プレイヤーの灯台契約を達成すると専門家報酬の抽選チャンス。</li></ul>',44)])])}const b=r(n,[["render",i]]);export{c as __pageData,b as default};
